INSERT INTO crm_email_templates (
    organization_id, name, subject, preview_text, body_html, body_plain,
    variables, generated_by, version, is_active, is_system, category, icon,
    suggested_subject, created_date, updated_date
) VALUES (
    NULL,
    'Scope 3 ESG Pitch',
    '*|FNAME|*, is your building ready for Scope 3 reporting?',
    'Scope 3 reporting deadlines are approaching — is your building portfolio ready?',
    E'
    <tr>
      <td align="center" style="padding-top: 40px; padding-right: 40px; padding-bottom: 20px; padding-left: 40px; background-color: #FFFFFF;">
        <img src="data:image/png;base64," alt="GEPP Intelligence" width="140" height="auto" style="display: block; border: 0; outline: none; max-width: 140px;" />
      </td>
    </tr>
    <tr>
      <td style="padding: 0; background-color: #CEDD42; height: 4px; font-size: 1px; line-height: 1px;">
        &nbsp;
      </td>
    </tr>
    <tr>
      <td style="padding-top: 48px; padding-right: 40px; padding-bottom: 48px; padding-left: 40px; background-color: #0A1F14;">
        <h1 style="margin: 0; padding: 0; font-family: Inter, -apple-system, BlinkMacSystemFont, ''Segoe UI'', Roboto, Helvetica, Arial, sans-serif; font-size: 28px; font-weight: 700; line-height: 1.2; color: #FFFFFF; text-align: center;">
          Measure What Others Estimate
        </h1>
        
        <p style="margin: 16px 0 0 0; padding: 0; font-family: Inter, -apple-system, BlinkMacSystemFont, ''Segoe UI'', Roboto, Helvetica, Arial, sans-serif; font-size: 16px; line-height: 1.6; color: rgba(255,255,255,0.65); text-align: center;">
          Hardware-verified Scope 3 emissions data for your building portfolio
        </p>
      </td>
    </tr>
    <tr>
      <td style="padding-top: 32px; padding-right: 40px; padding-bottom: 0; padding-left: 40px; background-color: #FFFFFF;">
        <p style="margin: 0; padding: 0; font-family: Inter, -apple-system, BlinkMacSystemFont, ''Segoe UI'', Roboto, Helvetica, Arial, sans-serif; font-size: 15px; line-height: 1.7; color: #0D1117; font-weight: 600;">
          Hi *|FNAME|*,
        </p>
      </td>
    </tr>
    <tr>
      <td style="padding-top: 32px; padding-right: 40px; padding-bottom: 8px; padding-left: 40px; background-color: #FFFFFF;">
        
        <p style="margin: 0 0 0 0; padding: 0; font-family: Inter, -apple-system, BlinkMacSystemFont, ''Segoe UI'', Roboto, Helvetica, Arial, sans-serif; font-size: 15px; line-height: 1.7; color: #475569;">
          For most companies, Scope 3 emissions represent over 90% of their total carbon footprint — yet most are still relying on spend-based estimates with error rates of 40% or more.<br><br>With EU CSRD now requiring Scope 3 disclosure and California SB 253 mandating reporting by 2027, the clock is ticking. Southeast Asian frameworks are converging on mandatory disclosure next.
        </p>
      </td>
    </tr>
    <tr>
      <td style="padding-top: 16px; padding-right: 40px; padding-bottom: 16px; padding-left: 40px; background-color: #FFFFFF;">
        <table role="presentation" width="100%" cellpadding="0" cellspacing="0" style="border-collapse: collapse;">
          <tr>
            <td style="padding-top: 20px; padding-right: 24px; padding-bottom: 20px; padding-left: 24px; background-color: #FFFBEB; border-left: 4px solid #F59E0B; border-radius: 8px;">
              
              <p style="margin: 0 0 8px 0; padding: 0; font-family: Inter, -apple-system, BlinkMacSystemFont, ''Segoe UI'', Roboto, Helvetica, Arial, sans-serif; font-size: 15px; font-weight: 700; color: #0D1117; line-height: 1.4;">
                Regulatory Timeline
              </p>
              <p style="margin: 0; padding: 0; font-family: Inter, -apple-system, BlinkMacSystemFont, ''Segoe UI'', Roboto, Helvetica, Arial, sans-serif; font-size: 14px; color: #475569; line-height: 1.6;">
                EU CSRD requires Scope 3 disclosure from 2025 for ~50,000 companies. California SB 253 mandates disclosure by 2027 for companies with $1B+ revenue. ASEAN frameworks are converging next.
              </p>
            </td>
          </tr>
        </table>
      </td>
    </tr>
    <tr>
      <td style="padding-top: 16px; padding-right: 40px; padding-bottom: 8px; padding-left: 40px; background-color: #FFFFFF;">
        
        <p style="margin: 0 0 0 0; padding: 0; font-family: Inter, -apple-system, BlinkMacSystemFont, ''Segoe UI'', Roboto, Helvetica, Arial, sans-serif; font-size: 15px; line-height: 1.7; color: #475569;">
          GEPP Intelligence replaces guesswork with hardware-verified emissions data. Our IoT sensors capture actual waste flows at source, and our platform automatically calculates Scope 3 emissions from operational data — not industry averages.
        </p>
      </td>
    </tr>
    <tr>
      <td style="padding-top: 16px; padding-right: 40px; padding-bottom: 16px; padding-left: 40px; background-color: #FFFFFF;">
        <table role="presentation" width="100%" cellpadding="0" cellspacing="0" style="border-collapse: collapse;">
          <tr>
            
            <td width="520" align="center" style="padding-top: 16px; padding-right: 8px; padding-bottom: 16px; padding-left: 8px; background-color: #F7F8F6; border-radius: 8px;">
              <p style="margin: 0; padding: 0; font-family: ''Courier New'', Courier, monospace; font-size: 28px; font-weight: 700; color: #13754A; line-height: 1.2;">
                
              </p>
              <p style="margin: 6px 0 0 0; padding: 0; font-family: Inter, -apple-system, BlinkMacSystemFont, ''Segoe UI'', Roboto, Helvetica, Arial, sans-serif; font-size: 12px; color: #94A3B8; line-height: 1.4;">
                
              </p>
            </td>
          </tr>
        </table>
      </td>
    </tr>
