INSERT INTO crm_email_templates (
    organization_id, name, subject, preview_text, body_html, body_plain,
    variables, generated_by, version, is_active, is_system, category, icon,
    suggested_subject, created_date, updated_date
) VALUES (
    NULL,
    'Case Study Share',
    'How [Client] achieved [Result] with GEPP Intelligence',
    'See how a leading property manager achieved 58% landfill reduction with GEPP.',
    E'
    <tr>
      <td align="center" style="padding-top: 40px; padding-right: 40px; padding-bottom: 20px; padding-left: 40px; background-color: #FFFFFF;">
        <img src="data:image/png;base64," alt="GEPP Intelligence" width="140" height="auto" style="display: block; border: 0; outline: none; max-width: 140px;" />
      </td>
    </tr>
    <tr>
      <td style="padding: 0; background-color: #CEDD42; height: 4px; font-size: 1px; line-height: 1px;">
        &nbsp;
      </td>
    </tr>
    <tr>
      <td style="padding-top: 48px; padding-right: 40px; padding-bottom: 48px; padding-left: 40px; background-color: #0A1F14;">
        <h1 style="margin: 0; padding: 0; font-family: Inter, -apple-system, BlinkMacSystemFont, ''Segoe UI'', Roboto, Helvetica, Arial, sans-serif; font-size: 28px; font-weight: 700; line-height: 1.2; color: #FFFFFF; text-align: center;">
          Real Results From Real Facilities
        </h1>
        
        <p style="margin: 16px 0 0 0; padding: 0; font-family: Inter, -apple-system, BlinkMacSystemFont, ''Segoe UI'', Roboto, Helvetica, Arial, sans-serif; font-size: 16px; line-height: 1.6; color: rgba(255,255,255,0.65); text-align: center;">
          See how GEPP Intelligence delivers measurable impact
        </p>
      </td>
    </tr>
    <tr>
      <td style="padding-top: 32px; padding-right: 40px; padding-bottom: 0; padding-left: 40px; background-color: #FFFFFF;">
        <p style="margin: 0; padding: 0; font-family: Inter, -apple-system, BlinkMacSystemFont, ''Segoe UI'', Roboto, Helvetica, Arial, sans-serif; font-size: 15px; line-height: 1.7; color: #0D1117; font-weight: 600;">
          Hi *|FNAME|*,
        </p>
      </td>
    </tr>
    <tr>
      <td style="padding-top: 32px; padding-right: 40px; padding-bottom: 32px; padding-left: 40px; background-color: #FFFFFF;">
        
        <p style="margin: 0 0 0 0; padding: 0; font-family: Inter, -apple-system, BlinkMacSystemFont, ''Segoe UI'', Roboto, Helvetica, Arial, sans-serif; font-size: 15px; line-height: 1.7; color: #475569;">
          Client: Assetwise Pub Co., Ltd. | Industry: Real Estate / Property Management
        </p>
        <p style="margin: 16px 0 0 0; padding: 0; font-family: Inter, -apple-system, BlinkMacSystemFont, ''Segoe UI'', Roboto, Helvetica, Arial, sans-serif; font-size: 15px; line-height: 1.7; color: #475569;">
          Like many property managers in Southeast Asia, the client struggled with manual waste tracking, inconsistent reporting, and no visibility into their environmental impact. Quarterly audits were producing stale data that couldn''t drive real decisions.
        </p>
      </td>
    </tr>
    <tr>
      <td style="padding-top: 16px; padding-right: 40px; padding-bottom: 16px; padding-left: 40px; background-color: #FFFFFF;">
        <table role="presentation" width="100%" cellpadding="0" cellspacing="0" style="border-collapse: collapse;">
          <tr>
            
            <td width="520" align="center" style="padding-top: 16px; padding-right: 8px; padding-bottom: 16px; padding-left: 8px; background-color: #F7F8F6; border-radius: 8px;">
              <p style="margin: 0; padding: 0; font-family: ''Courier New'', Courier, monospace; font-size: 28px; font-weight: 700; color: #13754A; line-height: 1.2;">
                
              </p>
              <p style="margin: 6px 0 0 0; padding: 0; font-family: Inter, -apple-system, BlinkMacSystemFont, ''Segoe UI'', Roboto, Helvetica, Arial, sans-serif; font-size: 12px; color: #94A3B8; line-height: 1.4;">
                
              </p>
            </td>
          </tr>
        </table>
      </td>
    </tr>
    <tr>
      <td style="padding-top: 16px; padding-right: 40px; padding-bottom: 8px; padding-left: 40px; background-color: #FFFFFF;">
        
        <p style="margin: 0 0 0 0; padding: 0; font-family: Inter, -apple-system, BlinkMacSystemFont, ''Segoe UI'', Roboto, Helvetica, Arial, sans-serif; font-size: 15px; line-height: 1.7; color: #475569;">
          After implementing GEPP Intelligence across their residential properties, the client saw dramatic improvements in waste diversion, cost reduction, and resident engagement with proper waste sorting practices.
        </p>
      </td>
    </tr>
    <tr>
      <td style="padding-top: 16px; padding-right: 40px; padding-bottom: 16px; padding-left: 40px; background-color: #FFFFFF;">
        <table role="presentation" width="100%" cellpadding="0" cellspacing="0" style="border-collapse: collapse;">
          <tr>
            <td style="padding-top: 20px; padding-right: 24px; padding-bottom: 20px; padding-left: 24px; border-left: 4px solid #CEDD42; background-color: #F7F8F6; border-radius: 0 8px 8px 0;">
              <p style="margin: 0; padding: 0; font-family: Inter, -apple-system, BlinkMacSystemFont, ''Segoe UI'', Roboto, Helvetica, Arial, sans-serif; font-size: 15px; font-style: italic; color: #0D1117; line-height: 1.6;">
                &ldquo;GEPP Intelligence gave us measurable waste metrics and helped educate our residents on proper waste sorting practices.&rdquo;
              </p>
              
              <p style="margin: 10px 0 0 0; padding: 0; font-family: Inter, -apple-system, BlinkMacSystemFont, ''Segoe UI'', Roboto, Helvetica, Arial, sans-serif; font-size: 13px; font-weight: 600; color: #94A3B8;">
                &mdash; Mr. Marupong Kitkasikorn, Assetwise Pub Co., Ltd.
              </p>
            </td>
          </tr>
        </table>
      </td>
    </tr>
    <tr>
      <td align="center" style="padding-top: 8px; padding-right: 40px; padding-bottom: 32px; padding-left: 40px; background-color: #FFFFFF;">
        <!--[if mso]>
        <v:roundrect xmlns:v="urn:schemas-microsoft-com:vml" xmlns:w="urn:schemas-microsoft-com:office:word" href="https://gepp.me/case-studies" style="height:48px;v-text-anchor:middle;width:220px;" arcsize="15%" strokecolor="#13754A" fillcolor="#13754A">
        <w:anchorlock/>
        <center style="color:#FFFFFF;font-family:Inter, -apple-system, BlinkMacSystemFont, ''Segoe UI'', Roboto, Helvetica, Arial, sans-serif;font-size:15px;font-weight:bold;">Read the Full Case Study</center>
        </v:roundrect>
